 79→/**
 80→ * Distance Haversine en kilometres.
 81→ */
 82→export const haversineKm = (
 83→  lat1: number,
 84→  lng1: number,
 85→  lat2: number,
 86→  lng2: number,
 87→): number => {
 88→  const toRad = (deg: number): number => (deg * Math.PI) / 180;
 89→  const earthRadiusKm = 6371;
 90→  const dLat = toRad(lat2 - lat1);
 91→  const dLng = toRad(lng2 - lng1);
 92→  const a =
 93→    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
 94→    Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng / 2) * Math.sin(dLng / 2);
 95→  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
 96→  return earthRadiusKm * c;
 97→};
